63	export function useVoiceEngine({
64	  onTranscript,
65	  onTTSStart,
66	  onTTSEnd,
67	  followUpWindowMs = FOLLOW_UP_MS,
68	  ttsUrl = '/api/tts',
69	  autoStart = true,
70	  useWhisper = false,
71	}: VoiceEngineOptions): VoiceEngineReturn {
72	  const [voiceState, setVoiceState] = useState<VoiceState>('dormant');
73	  const [interim, setInterim] = useState('');
74	  const [micLevel, setMicLevel] = useState(0);
75	  const [ttsLevel, setTtsLevel] = useState(0);
76	  const [supported, setSupported] = useState(false);
77	  const [micError, setMicError] = useState<string | null>(null);
78	
79	  // Restart storm prevention (#V1) — cap restarts, reset after quiet period
80	  const restartCountRef = useRef(0);
81	  const restartResetTimerRef = useRef<ReturnType<typeof setTimeout> | null>(null);
82	
83	  const stateRef = useRef<VoiceState>('dormant');
84	  const recogRef = useRef<SpeechRecognitionInstance | null>(null);
85	  const followUpTimer = useRef<ReturnType<typeof setTimeout> | null>(null);
86	  const audioCtxRef = useRef<AudioContext | null>(null);
87	  const micStreamRef = useRef<MediaStream | null>(null);
88	  const analyserRef = useRef<AnalyserNode | null>(null);
89	  const micAnimRef = useRef<number | null>(null);
90	  const ttsSourceRef = useRef<AudioBufferSourceNode | null>(null);
91	  const ttsCtxRef = useRef<AudioContext | null>(null);
92	  const ttsAnimRef = useRef<number | null>(null);
93	  const mutedRef = useRef(false);
94	  const restartTimerRef = useRef<ReturnType<typeof setTimeout> | null>(null);
95	
96	  // Whisper recording refs (only used when useWhisper=true)
97	  const mediaRecorderRef = useRef<MediaRecorder | null>(null);
98	  const audioChunksRef = useRef<Blob[]>([]);
99	  const silenceTimerRef = useRef<ReturnType<typeof setTimeout> | null>(null);
100	
101	  // Stale-closure avoidance: callbacks read stateRef instead of voiceState
102	  const setState = useCallback((s: VoiceState) => {
103	    stateRef.current = s;
104	    setVoiceState(s);
105	  }, []);
106	
107	  // ── Shared AudioContext ────────────────────────────────────────────────────
108	  const getAudioCtx = useCallback(() => {
109	    if (!audioCtxRef.current || audioCtxRef.current.state === 'closed') {
110	      audioCtxRef.current = new AudioContext();
111	    }
112	    return audioCtxRef.current;
113	  }, []);
114	
115	  // ── Mic level analyzer ─────────────────────────────────────────────────────
116	  const startMicAnalyzer = useCallback(async () => {
117	    try {
118	      const ctx = getAudioCtx();
119	      if (!micStreamRef.current) {
120	        micStreamRef.current = await navigator.mediaDevices.getUserMedia({ audio: true, video: false });
121	      }
122	      setMicError(null); // clear any previous error
123	      analyserRef.current?.disconnect();
124	      const src = ctx.createMediaStreamSource(micStreamRef.current);
125	      analyserRef.current = ctx.createAnalyser();
126	      analyserRef.current.fftSize = 128;
127	      src.connect(analyserRef.current);
128	      startLevelTick(analyserRef.current, setMicLevel, micAnimRef);
129	    } catch (e) {
130	      // Surface permission/device errors to UI instead of swallowing (#V1)
131	      const msg = e instanceof Error ? e.message : String(e);
132	      const friendly = msg.toLowerCase().includes('permission')
133	        ? 'Microphone access denied — please allow mic access and try again'
134	        : msg.toLowerCase().includes('not found') || msg.toLowerCase().includes('device')
135	        ? 'No microphone found — please connect one and try again'
136	        : 'Microphone unavailable';
137	      setMicError(friendly);
138	      setState('error');
139	      console.warn('[VoiceEngine] Mic error:', e);
140	    }
141	  }, [getAudioCtx, setState]);
142	
143	  const stopMicAnalyzer = useCallback(() => {
144	    if (micAnimRef.current) {
145	      cancelAnimationFrame(micAnimRef.current);
146	      micAnimRef.current = null;
147	      setMicLevel(0);
148	    }
149	  }, []);
150	
151	  // ── Follow-up window ──────────────────────────────────────────────────────
152	  const clearFollowUp = useCallback(() => {
153	    if (followUpTimer.current) clearTimeout(followUpTimer.current);
154	  }, []);
155	
156	  const enterFollowUp = useCallback(() => {
157	    setState('followup');
158	    clearFollowUp();
159	    followUpTimer.current = setTimeout(() => {
160	      if (stateRef.current === 'followup') setState('dormant');
161	    }, followUpWindowMs);
162	  }, [setState, clearFollowUp, followUpWindowMs]);
163	
164	  // ── TTS playback ──────────────────────────────────────────────────────────
165	  const stopSpeaking = useCallback(() => {
166	    ttsSourceRef.current?.stop();
167	    ttsSourceRef.current = null;
168	    if (ttsAnimRef.current) {
169	      cancelAnimationFrame(ttsAnimRef.current);
170	      ttsAnimRef.current = null;
171	    }
172	    // Close the dedicated TTS AudioContext to prevent leaks
173	    if (ttsCtxRef.current) {
174	      ttsCtxRef.current.close().catch(() => {});
175	      ttsCtxRef.current = null;
176	    }
177	    setTtsLevel(0);
178	  }, []);
179	
180	  const speakText = useCallback(async (text: string): Promise<void> => {
181	    if (!text?.trim()) { enterFollowUp(); return; }
182	    stopSpeaking();
183	    setState('speaking');
184	    onTTSStart?.();
185	
186	    try {
187	      const res = await fetch(ttsUrl, {
188	        method: 'POST',
189	        headers: { 'Content-Type': 'application/json' },
190	        body: JSON.stringify({ text: text.slice(0, 2000) }),
191	      });
192	      const data = await res.json();
193	
194	      if (!data.audio) throw new Error('No audio returned');
195	
196	      const raw = atob(data.audio);
197	      const bytes = new Uint8Array(raw.length);
198	      for (let i = 0; i < raw.length; i++) bytes[i] = raw.charCodeAt(i);
199	
200	      // Dedicated context for TTS — tracked in ttsCtxRef for cleanup
201	      const ctx = new AudioContext();
202	      ttsCtxRef.current = ctx;
203	      const buffer = await ctx.decodeAudioData(bytes.buffer);
204	
205	      const analyser = ctx.createAnalyser();
206	      analyser.fftSize = 128;
207	
208	      const src = ctx.createBufferSource();
209	      src.buffer = buffer;
210	      src.connect(analyser);
211	      analyser.connect(ctx.destination);
212	      ttsSourceRef.current = src;
213	
214	      startLevelTick(analyser, setTtsLevel, ttsAnimRef);
215	
216	      src.start();
217	      src.onended = () => {
218	        if (ttsAnimRef.current) cancelAnimationFrame(ttsAnimRef.current);
219	        ttsAnimRef.current = null;
220	        setTtsLevel(0);
221	        ctx.close().catch(() => {});
222	        ttsCtxRef.current = null;
223	        onTTSEnd?.();
224	        enterFollowUp();
225	      };
226	    } catch (e) {
227	      console.warn('[VoiceEngine] TTS error:', e);
228	      onTTSEnd?.();
229	      enterFollowUp();
230	    }
231	  }, [ttsUrl, stopSpeaking, setState, enterFollowUp, onTTSStart, onTTSEnd]);
232	
233	  // ── Speech recognition ────────────────────────────────────────────────────
234	  const stopRecognition = useCallback(() => {
235	    try { recogRef.current?.stop(); } catch { /* ignore */ }
236	  }, []);
237	
238	  const startRecognition = useCallback(() => {
239	    const SR = getSpeechRecognitionConstructor();
240	    if (!SR) return;
241	
242	    stopRecognition();
243	
244	    const r = new SR();
245	    r.continuous = true;
246	    r.interimResults = true;
247	    r.lang = 'en-US';
248	    r.maxAlternatives = 1;
249	    recogRef.current = r;
250	
251	    let finalBuffer = '';
252	    let silenceTimer: ReturnType<typeof setTimeout> | null = null;
253	
254	    const resetSilence = () => {
255	      if (silenceTimer) clearTimeout(silenceTimer);
256	      silenceTimer = setTimeout(() => {
257	        if (finalBuffer.trim().length >= MIN_SPEECH_CHARS &&
258	            (stateRef.current === 'listening' || stateRef.current === 'followup')) {
259	          const text = finalBuffer.trim();
260	          finalBuffer = '';
261	          setInterim('');
262	          stopMicAnalyzer();
263	          setState('thinking');
264	          onTranscript(text);
265	        }
266	      }, SILENCE_COMMIT_MS);
267	    };
268	
269	    r.onresult = (e: SpeechRecognitionEventLike) => {
270	      let interimText = '';
271	      let newFinal = '';
272	
273	      for (let i = e.resultIndex; i < e.results.length; i++) {
274	        const t = e.results[i][0].transcript;
275	        if (e.results[i].isFinal) newFinal += t + ' ';
276	        else interimText += t;
277	      }
278	
279	      if (newFinal) {
280	        finalBuffer += newFinal;
281	        resetSilence();
282	      }
283	
284	      setInterim((finalBuffer + interimText).trim());
285	
286	      if (stateRef.current === 'dormant') {
287	        const all = (finalBuffer + interimText).toLowerCase();
288	        if (WAKE_WORDS.some(w => all.includes(w))) {
289	          finalBuffer = '';
290	          setInterim('');
291	          setState('listening');
292	          startMicAnalyzer();
293	        }
294	      }
295	    };
296	
297	    r.onspeechstart = () => {
298	      if (stateRef.current === 'dormant') return;
299	      if (stateRef.current === 'followup') {
300	        clearFollowUp();
301	        setState('listening');
302	        startMicAnalyzer();
303	      }
304	    };
305	
306	    r.onerror = (e: SpeechRecognitionErrorEventLike) => {
307	      if (e.error === 'no-speech' || e.error === 'aborted') return;
308	      console.warn('[VoiceEngine] Recognition error:', e.error);
309	    };
310	
311	    r.onend = () => {
312	      if (!mutedRef.current &&
313	          stateRef.current !== 'thinking' &&
314	          stateRef.current !== 'speaking' &&
315	          stateRef.current !== 'error') {
316	        // Cap restarts to prevent infinite storm (#V1)
317	        restartCountRef.current++;
318	        if (restartCountRef.current > MAX_VOICE_RESTARTS) {
319	          setState('error');
320	          setMicError('Voice recognition is having trouble — click the mic to try again');
321	          // Auto-reset the counter after quiet period so user can retry
322	          if (restartResetTimerRef.current) clearTimeout(restartResetTimerRef.current);
323	          restartResetTimerRef.current = setTimeout(() => {
324	            restartCountRef.current = 0;
325	            restartResetTimerRef.current = null;
326	          }, VOICE_RESTART_RESET_MS);
327	          return;
328	        }
329	        restartTimerRef.current = setTimeout(() => {
330	          restartTimerRef.current = null;
331	          if (!mutedRef.current) startRecognition();
332	        }, 200);
333	      }
334	    };
335	
336	    try { r.start(); } catch { /* already running */ }
337	  }, [stopRecognition, stopMicAnalyzer, setState, startMicAnalyzer, onTranscript, clearFollowUp]);
338	
339	  // ── Whisper recording ─────────────────────────────────────────────────────
340	  const startWhisperRecording = useCallback(async () => {
341	    try {
342	      const stream = await navigator.mediaDevices.getUserMedia({ audio: true });
343	      micStreamRef.current = stream;
344	      const recorder = new MediaRecorder(stream, { mimeType: 'audio/webm' });
345	      audioChunksRef.current = [];
346	      mediaRecorderRef.current = recorder;
347	
348	      recorder.ondataavailable = (e) => {
349	        if (e.data.size > 0) audioChunksRef.current.push(e.data);
350	      };
351	
352	      recorder.onstop = async () => {
353	        const blob = new Blob(audioChunksRef.current, { type: 'audio/webm' });
354	        audioChunksRef.current = [];
355	        if (blob.size < 1000) { setState('listening'); startWhisperRecording(); return; }
356	
357	        setState('thinking');
358	        const form = new FormData();
359	        form.append('audio', blob, 'recording.webm');
360	        try {
361	          const correlationId = generateCorrelationId();
362	          const res = await fetch('/api/stt', {
363	            method: 'POST',
364	            body: form,
365	            headers: { [CORRELATION_HEADER]: correlationId },
366	          });
367	          const data = await res.json();
368	          if (data.text?.trim()) {
369	            // If Whisper flagged low confidence, we still pass through but
370	            // the caller can optionally display a clarification prompt (#V3)
371	            onTranscript(data.text.trim(), data.lowConfidence === true);
372	          } else {
373	            setState('listening');
374	            startWhisperRecording();
375	          }
376	        } catch {
377	          setState('listening');
378	          startWhisperRecording();
379	        }
380	      };
381	
382	      recorder.start(100); // collect chunks every 100ms
383	
384	      // Silence detection via analyser
385	      const ctx = getAudioCtx();
386	      const src = ctx.createMediaStreamSource(stream);
387	      const analyser = ctx.createAnalyser();
388	      analyser.fftSize = 128;
389	      src.connect(analyser);
390	      analyserRef.current = analyser;
391	      startLevelTick(analyser, setMicLevel, micAnimRef);
392	
393	      const buf = new Uint8Array(analyser.frequencyBinCount);
394	      const checkSilence = () => {
395	        analyser.getByteFrequencyData(buf);
396	        const avg = buf.reduce((a, b) => a + b, 0) / buf.length;
397	        if (avg < 5) {
398	          if (!silenceTimerRef.current) {
399	            silenceTimerRef.current = setTimeout(() => {
400	              silenceTimerRef.current = null;
401	              if (mediaRecorderRef.current?.state === 'recording') {
402	                stopMicAnalyzer();
403	                mediaRecorderRef.current.stop();
404	              }
405	            }, 1500);
406	          }
407	        } else {
408	          if (silenceTimerRef.current) {
409	            clearTimeout(silenceTimerRef.current);
410	            silenceTimerRef.current = null;
411	          }
412	        }
413	        if (stateRef.current === 'listening') requestAnimationFrame(checkSilence);
414	      };
415	      requestAnimationFrame(checkSilence);
416	    } catch (e) {
417	      console.warn('[VoiceEngine] Whisper recording failed:', e);
418	    }
419	  }, [getAudioCtx, onTranscript, setState, stopMicAnalyzer]);
420	
421	  // ── Public controls ───────────────────────────────────────────────────────
422	  const wakeUp = useCallback(() => {
423	    clearFollowUp();
424	    setState('listening');
425	    startMicAnalyzer();
426	  }, [setState, clearFollowUp, startMicAnalyzer]);
427	
428	  const toggle = useCallback(() => {
429	    if (stateRef.current === 'dormant') {
430	      mutedRef.current = false;
431	      if (useWhisper) {
432	        setState('listening');
433	        startWhisperRecording();
434	      } else {
435	        wakeUp();
436	        startRecognition();
437	      }
438	    } else {
439	      mutedRef.current = true;
440	      if (useWhisper) {
441	        if (silenceTimerRef.current) {
442	          clearTimeout(silenceTimerRef.current);
443	          silenceTimerRef.current = null;
444	        }
445	        if (mediaRecorderRef.current?.state === 'recording') {
446	          mediaRecorderRef.current.stop();
447	        }
448	        mediaRecorderRef.current = null;
449	      } else {
450	        stopRecognition();
451	      }
452	      stopSpeaking();
453	      stopMicAnalyzer();
454	      clearFollowUp();
455	      setState('dormant');
456	    }
457	  }, [useWhisper, wakeUp, startRecognition, startWhisperRecording, stopRecognition, stopSpeaking, stopMicAnalyzer, clearFollowUp, setState]);
458	
459	  // ── Init ──────────────────────────────────────────────────────────────────
460	  useEffect(() => {
461	    const hasSR = typeof window !== 'undefined' &&
462	      !!getSpeechRecognitionConstructor();
463	    setSupported(useWhisper ? true : hasSR);
464	    if (!autoStart) return;
465	
466	    if (useWhisper) {
467	      const t = setTimeout(() => {
468	        mutedRef.current = false;
469	        setState('listening');
470	        startWhisperRecording();
471	      }, 800);
472	      return () => {
473	        clearTimeout(t);
474	        if (silenceTimerRef.current) clearTimeout(silenceTimerRef.current);
475	        if (mediaRecorderRef.current?.state === 'recording') mediaRecorderRef.current.stop();
476	        mutedRef.current = true;
477	        stopMicAnalyzer();
478	        clearFollowUp();
479	      };
480	    }
481	
482	    if (!hasSR) return;
483	
484	    const t = setTimeout(() => {
485	      mutedRef.current = false;
486	      startRecognition();
487	      setState('listening');
488	      startMicAnalyzer();
489	    }, 800);
490	
491	    return () => {
492	      clearTimeout(t);
493	      if (restartTimerRef.current) clearTimeout(restartTimerRef.current);
494	      mutedRef.current = true;
495	      stopRecognition();
496	      stopMicAnalyzer();
497	      clearFollowUp();
498	    };
499	    // eslint-disable-next-line react-hooks/exhaustive-deps
500	  }, []);
501	
502	  // Restart recognition whenever we enter listening or followup.
503	  // recogRef is never nulled after first start, so we can't use it as a
504	  // "is running" guard — always restart to ensure the mic is live.
505	  useEffect(() => {
506	    if (!useWhisper && (voiceState === 'listening' || voiceState === 'followup')) {
507	      startRecognition();
508	    }
509	  }, [useWhisper, voiceState, startRecognition]);
510	
511	  return { voiceState, interim, micLevel, ttsLevel, supported, micError, toggle, speakText, stopSpeaking, wakeUp };
512	}
